import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.Cnz97o_5.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1782491094000}'),n={name:"guide/introduction.md"};function r(s,e,l,d,h,c){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>pyworkforce</strong> is a Python package with tools for workforce management problems such as queue staffing, shift scheduling, rostering and operations-research optimization. It is especially well suited to contact / call centers, but the same techniques apply to hospitals, retail, logistics, network capacity planning and any operation that has to match a variable demand with a finite number of resources.</p><p>The package is organized around three planning steps that usually happen in sequence:</p><h2 id="_1-queuing-—-how-many-resources-do-i-need" tabindex="-1">1. Queuing — <em>how many resources do I need?</em> <a class="header-anchor" href="#_1-queuing-—-how-many-resources-do-i-need" aria-label="Permalink to &quot;1. Queuing — *how many resources do I need?*&quot;">​</a></h2><p>Given an incoming demand (for example, calls arriving at a call center), how many agents or channels are required to hit a service target?</p><ul><li><a href="/development/guide/erlangc"><code>ErlangC</code></a> — the classic M/M/c queue: Poisson arrivals, exponential handling times, an infinite queue and no abandonment.</li><li><a href="/development/guide/erlanga"><code>ErlangA</code></a> — the M/M/c+M queue, which additionally models customers who <strong>abandon</strong> the queue if they wait too long. This is closer to reality for most contact centers.</li><li><a href="/development/guide/erlangb"><code>ErlangB</code></a> — the M/M/c/c <strong>loss queue</strong>: no waiting room, blocked calls are shed. Use this for trunk / SIP channel sizing.</li><li><a href="/development/guide/multierlang"><code>MultiErlangC</code></a> / <code>MultiErlangA</code> / <code>MultiErlangB</code> — evaluate many scenarios at once from a parameter grid, with a scikit-learn-like interface.</li></ul><h2 id="_2-staffing-—-what-is-the-optimal-skill-mix" tabindex="-1">2. Staffing — <em>what is the optimal skill mix?</em> <a class="header-anchor" href="#_2-staffing-—-what-is-the-optimal-skill-mix" aria-label="Permalink to &quot;2. Staffing — *what is the optimal skill mix?*&quot;">​</a></h2><p>When your team handles multiple contact types (languages, queues, skill groups), you need to decide how many agents of each skill profile to hire so that every skill&#39;s coverage requirement is met at the lowest possible cost.</p><ul><li><a href="/development/guide/staffing"><code>MultiSkillStaffing</code></a> — solves the integer programme that minimises total weighted headcount given per-skill requirements. Flexible (multi-skilled) agents count towards every skill they hold, so the solver automatically trades off dedicated vs. flexible hiring.</li></ul><h2 id="_3-scheduling-—-how-many-people-per-shift" tabindex="-1">3. Scheduling — <em>how many people per shift?</em> <a class="header-anchor" href="#_3-scheduling-—-how-many-people-per-shift" aria-label="Permalink to &quot;3. Scheduling — *how many people per shift?*&quot;">​</a></h2><p>Once you know the resources required per period of the day, decide how many people to place on each predefined shift.</p><ul><li><a href="/development/guide/scheduling"><code>MinAbsDifference</code></a> — minimize the absolute difference between required and scheduled resources.</li><li><a href="/development/guide/scheduling"><code>MinRequiredResources</code></a> — minimize the (optionally weighted) number of scheduled resources while covering every period.</li></ul><p>The <a href="/development/guide/shifts">shift coverage builders</a> help you create the <code>shifts_coverage</code> definitions these solvers expect without writing 0/1 arrays by hand.</p><h2 id="_4-rostering-—-who-works-when" tabindex="-1">4. Rostering — <em>who works when?</em> <a class="header-anchor" href="#_4-rostering-—-who-works-when" aria-label="Permalink to &quot;4. Rostering — *who works when?*&quot;">​</a></h2><p>Assign <strong>named</strong> resources to days and shifts while respecting rules such as banned shifts, rest days, minimum working hours, non-sequential shifts and personal preferences.</p><ul><li><a href="/development/guide/rostering"><code>MinHoursRoster</code></a> — build a resource-level roster that covers the shift requirements with the minimum scheduled hours.</li></ul><h2 id="_5-break-scheduling-—-when-do-breaks-happen" tabindex="-1">5. Break scheduling — <em>when do breaks happen?</em> <a class="header-anchor" href="#_5-break-scheduling-—-when-do-breaks-happen" aria-label="Permalink to &quot;5. Break scheduling — *when do breaks happen?*&quot;">​</a></h2><p>Once the roster is set, assign a start time to every break for every agent slot while ensuring that simultaneous breaks never drop coverage below the required minimum.</p><ul><li><a href="/development/guide/breaks"><code>BreakScheduler</code></a> — CP-SAT solver that places breaks inside shift windows, prevents overlaps, and respects per-period coverage constraints.</li></ul><h2 id="design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design principles&quot;">​</a></h2><p>pyworkforce aims for a <strong>scikit-learn level of friendliness</strong>:</p><ul><li>consistent constructors and clear, actionable error messages;</li><li><code>get_params()</code> and readable <code>repr()</code> on every estimator;</li><li>the last result is stored on the estimator (<code>solution_</code>) after solving;</li><li>deterministic, well-tested numerical methods.</li></ul><p>Ready? Head to <a href="/development/guide/installation">Installation</a> and the <a href="/development/guide/quickstart">Quick Start</a>, or jump straight into the <a href="/development/guide/end-to-end">end-to-end tutorial</a>.</p>',23)])])}const m=a(n,[["render",r]]);export{p as __pageData,m as default};
